  ('course-agentic', 'cat-ai', 'Agentic AI Systems', 'agentic-ai-systems', 'Design autonomous, tool-using AI agents.', 'Build agents with planning, memory and tool use.', 'https://images.unsplash.com/photo-1526374965328-7f61d4dc18c5?auto=format&fit=crop&w=800&q=60', 'advanced', 'AI,Agents', 120, 0, NULL, 1, 0, 1, 'allLessons', 100, 'published', strftime('%s','now')),
